kernel void dynproc_kernel(
    int iteration,
    const int *gpuWall,
    const int *gpuSrc,
    int *gpuResults,
    int cols,
    int rows,
    int startStep,
    int border,
    int halo,
    local int *prev,
    local int *result,
    int *outputBuffer)
{
    int bx = get_block_id(0);
    int tx = get_local_id(0);

    int small_block_cols = 256 - iteration * halo * 2;

    int blkX = small_block_cols * bx - border;
    int blkXmax = blkX + 256 - 1;

    int xidx = blkX + tx;

    int validXmin = (blkX < 0) ? -blkX : 0;
    int validXmax = (blkXmax > cols - 1) ? 256 - 1 - (blkXmax - cols + 1) : 256 - 1;

    int W = tx - 1;
    int E = tx + 1;

    W = (W < validXmin) ? validXmin : W;
    E = (E > validXmax) ? validXmax : E;

    int isValid = (tx >= validXmin && tx <= validXmax) ? 1 : 0;

    if (xidx >= 0 && xidx <= cols - 1) {
        prev[tx] = gpuSrc[xidx];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    int computed = 0;
    for (int i = 0; i < iteration; i++) {
        computed = 0;
        if ((tx >= i + 1 && tx <= 256 - i - 2) && isValid) {
            computed = 1;
            int left = prev[W];
            int up = prev[tx];
            int right = prev[E];
            int shortest = (left <= up) ? left : up;
            shortest = (shortest <= right) ? shortest : right;
            int index = cols * (startStep + i) + xidx;
            result[tx] = shortest + gpuWall[index];
        }
        barrier(CLK_LOCAL_MEM_FENCE);
        if (i == iteration - 1)
            break;
        if (computed)
            prev[tx] = result[tx];
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    if (computed && xidx >= 0 && xidx <= cols - 1) {
        gpuResults[xidx] = result[tx];
    }

    if (tx == 0 && bx == 0) {
        outputBuffer[0] = 1;
    }
}
